import { useState, useEffect } from 'react';

const links = ['about', 'projects', 'experience', 'certs', 'contact'];

export default function Navbar() {
  const [scrolled, setScrolled] = useState(false);
  const [active, setActive] = useState('');
  const [menuOpen, setMenuOpen] = useState(false);

  useEffect(() => {
    const onScroll = () => {
      setScrolled(window.scrollY > 40);
      let cur = '';
      document.querySelectorAll('section[id]').forEach(s => {
        if (window.scrollY >= s.offsetTop - 130) cur = s.id;
      });
      setActive(cur);
    };
    window.addEventListener('scroll', onScroll, { passive: true });
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  return (
    <nav className={`fixed inset-x-0 top-0 z-50 flex items-center justify-between px-[5%] py-5 transition-all duration-300 ${scrolled ? 'bg-cream/90 backdrop-blur-lg shadow-sm border-b border-ink/5' : 'bg-transparent'}`}>
      <a href="#hero" className="font-serif-display text-2xl text-ink tracking-tight">
        Kareem<span className="text-amber">.</span>
      </a>

      {/* Desktop links */}
      <ul className="hidden md:flex gap-8">
        {links.map(l => (
          <li key={l}>
            <a
              href={`#${l}`}
              className={`text-sm font-medium capitalize transition-colors duration-200 ${active === l ? 'text-amber' : 'text-muted2 hover:text-amber'}`}
            >
              {l}
            </a>
          </li>
        ))}
      </ul>

      <a
        href="mailto:karemalwy1@gmail.com"
        className="hidden md:inline-block px-5 py-2 bg-ink text-parchment text-sm font-semibold rounded-full transition-all duration-200 hover:bg-amber hover:-translate-y-0.5"
      >
        Hire Me
      </a>

      {/* Mobile hamburger */}
      <button className="md:hidden flex flex-col gap-1.5" onClick={() => setMenuOpen(!menuOpen)}>
        <span className={`block w-6 h-0.5 bg-ink transition-all ${menuOpen ? 'rotate-45 translate-y-2' : ''}`} />
        <span className={`block w-6 h-0.5 bg-ink transition-all ${menuOpen ? 'opacity-0' : ''}`} />
        <span className={`block w-6 h-0.5 bg-ink transition-all ${menuOpen ? '-rotate-45 -translate-y-2' : ''}`} />
      </button>

      {/* Mobile menu */}
      {menuOpen && (
        <div className="absolute top-full left-0 right-0 bg-parchment border-b border-ink/10 py-4 flex flex-col items-center gap-4 md:hidden">
          {links.map(l => (
            <a key={l} href={`#${l}`} onClick={() => setMenuOpen(false)}
              className="text-sm font-medium capitalize text-muted2 hover:text-amber transition-colors">
              {l}
            </a>
          ))}
          <a href="mailto:karemalwy1@gmail.com" className="px-5 py-2 bg-ink text-parchment text-sm font-semibold rounded-full">
            Hire Me
          </a>
        </div>
      )}
    </nav>
  );
}
